mapper.select:
select 
  from batch.console_push_subscription
 where tenant_id = #{tenantId} and username = #{username}

mapper.delete:
delete from batch.console_push_subscription
 where tenant_id = #{tenantId}
   and username = #{username}
   and endpoint = #{endpoint}

mapper.update:
update batch.console_push_subscription
   set last_pushed_at = #{ts}
 where id = #{id}
